export type CircuitState = {
  consecutiveFailures: number;
  state: "open" | "closed";
};

export const CIRCUIT_BREAKER_CACHE_NAME = "circuit-breaker";
export const CIRCUIT_BREAKER_CACHE_TTL_SECONDS = 300;

export const getRunId = (): string => process.env.ZEALT_RUN_ID ?? "default";

export const getCircuitCacheKey = (runId: string = getRunId()): string =>
  `api-data:${runId}`;

export const createClosedState = (): CircuitState => ({
  consecutiveFailures: 0,
  state: "closed",
});

import {
  HttpProblems,
  ZoneCache,
  ZuploContext,
  ZuploRequest,
} from "@zuplo/runtime";

import {
  CIRCUIT_BREAKER_CACHE_NAME,
  CircuitState,
  createClosedState,
  getCircuitCacheKey,
} from "./circuit-breaker-state";

export default async function circuitBreakerInbound(
  request: ZuploRequest,
  context: ZuploContext,
) {
  const cache = new ZoneCache<CircuitState>(
    CIRCUIT_BREAKER_CACHE_NAME,
    context,
  );
  const cacheKey = getCircuitCacheKey();
  const currentState = (await cache.get(cacheKey)) ?? createClosedState();

  if (currentState.state === "open") {
    return HttpProblems.serviceUnavailable(request, context, {
      title: "Service Unavailable",
      detail: "Circuit breaker is open for this backend.",
    });
  }

  return request;
}

import { ZoneCache, ZuploContext, ZuploRequest } from "@zuplo/runtime";

import {
  CIRCUIT_BREAKER_CACHE_NAME,
  CIRCUIT_BREAKER_CACHE_TTL_SECONDS,
  CircuitState,
  createClosedState,
  getCircuitCacheKey,
} from "./circuit-breaker-state";

const FAILURE_THRESHOLD = 5;

export default async function circuitBreakerOutbound(
  response: Response,
  _request: ZuploRequest,
  context: ZuploContext,
) {
  const cache = new ZoneCache<CircuitState>(
    CIRCUIT_BREAKER_CACHE_NAME,
    context,
  );
  const cacheKey = getCircuitCacheKey();

  if (response.status >= 500) {
    const existingState = (await cache.get(cacheKey)) ?? createClosedState();
    const consecutiveFailures = existingState.consecutiveFailures + 1;
    const nextState: CircuitState = {
      consecutiveFailures,
      state: consecutiveFailures >= FAILURE_THRESHOLD ? "open" : "closed",
    };

    await cache.put(cacheKey, nextState, CIRCUIT_BREAKER_CACHE_TTL_SECONDS);
    return response;
  }

  await cache.put(cacheKey, createClosedState(), CIRCUIT_BREAKER_CACHE_TTL_SECONDS);
  return response;
}

